#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int K; scanf("%d", &K);
        // use a boolean marker array sized N+1 (N ≤ 100000)
        char *bad = (char*)calloc(N + 1, sizeof(char));
        for (int i = 0; i < K; ++i) {
            int x; scanf("%d", &x);
            if (x <= N) bad[x] = 1;
        }
        int first = 1;
        for (int i = 0; i < N; ++i) {
            if (!bad[A[i]]) {
                if (!first) printf(" ");
                printf("%d", A[i]);
                first = 0;
            }
        }
        printf("\n");
        free(A);
        free(bad);
    }
    return 0;
}

