const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const A = input.slice(idx, idx + N);
  idx += N;
  const K = input[idx++];
  const bad = new Set();
  for (let i = 0; i < K; i++) {
    bad.add(input[idx++]);
  }
  const res = [];
  for (const x of A) {
    if (!bad.has(x)) res.push(x);
  }
  outputs.push(res.join(' '));
}
